// ============================================
// WARMUP CONFIGURATION - EDIT THESE VALUES
// ============================================
const START_DATE = '2026-02-21'; // Set your warmup start date

const now = new Date();
const startDate = new Date(START_DATE);
const daysSinceStart = Math.floor((now - startDate) / (1000 * 60 * 60 * 24));
const week = Math.floor(daysSinceStart / 7) + 1;

// Gradual ramp-up schedule
const schedule = {
  1: { perDay: 3, replyRate: 100, weekendsOff: true },
  2: { perDay: 6, replyRate: 80, weekendsOff: true },
  3: { perDay: 12, replyRate: 70, weekendsOff: false },
  4: { perDay: 20, replyRate: 60, weekendsOff: false },
  5: { perDay: 30, replyRate: 50, weekendsOff: false },
  6: { perDay: 40, replyRate: 40, weekendsOff: false }
};

const config = schedule[Math.min(week, 6)];

// Business hours check (8 AM - 6 PM)
const hour = now.getHours();
const isBusinessHours = hour >= 8 && hour <= 18;

// Weekend check
const dayOfWeek = now.getDay();
const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const skipWeekend = config.weekendsOff && isWeekend;

return [{
  json: {
    week,
    daysSinceStart,
    emailsPerDay: config.perDay,
    replyRate: config.replyRate,
    shouldSend: isBusinessHours && !skipWeekend,
    currentHour: hour,
    isWeekend
  }
}];

// Track daily send count using workflow static data
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().split('T')[0];

// Reset counter each day
if (staticData.lastDate !== today) {
  staticData.lastDate = today;
  staticData.sentToday = 0;
}

const emailsPerDay = $input.first().json.emailsPerDay;
const canSend = staticData.sentToday < emailsPerDay;

return [{
  json: {
    ...$input.first().json,
    sentToday: staticData.sentToday,
    canSend,
    remaining: emailsPerDay - staticData.sentToday
  }
}];

// ============================================
// WARMUP PARTNERS - EDIT THIS LIST
// ============================================
// Add 5-10 email accounts YOU control
// Mix providers: Gmail, Outlook, Yahoo, custom domains

const warmupPartners = [
  { name: 'Alex', email: 'warmup1@yourdomain.com', provider: 'custom' },
  { name: 'Sarah', email: 'warmup2@gmail.com', provider: 'gmail' },
  { name: 'Mike', email: 'warmup3@outlook.com', provider: 'outlook' },
  { name: 'Lisa', email: 'warmup4@yourdomain.com', provider: 'custom' },
  { name: 'James', email: 'warmup5@yahoo.com', provider: 'yahoo' },
  { name: 'Emma', email: 'warmup6@gmail.com', provider: 'gmail' },
  { name: 'David', email: 'warmup7@outlook.com', provider: 'outlook' },
  { name: 'Nina', email: 'warmup8@yourdomain.com', provider: 'custom' }
];

// Rotate through partners evenly
const staticData = $getWorkflowStaticData('global');
const idx = (staticData.partnerIndex || 0) % warmupPartners.length;
staticData.partnerIndex = idx + 1;

const partner = warmupPartners[idx];

return [{
  json: {
    partnerName: partner.name,
    partnerEmail: partner.email,
    partnerProvider: partner.provider,
    week: $input.first().json.week,
    replyRate: $input.first().json.replyRate
  }
}];

// Generate realistic, human-like email content
// These look like genuine business conversations

const week = $input.first().json.week;
const partnerName = $input.first().json.partnerName;

// Subject lines - casual business tone
const subjects = [
  'Quick question about the project',
  'Following up on our discussion',
  'Meeting notes from today',
  'Resource you might find useful',
  'Thoughts on the proposal?',
  'Schedule for next week',
  'Interesting article I found',
  'Can we sync up tomorrow?',
  'Update on the deliverables',
  'Thanks for the introduction',
  'Re: Project timeline update',
  'Checking in on progress',
  'Quick favor to ask',
  'Feedback on the draft',
  'Idea for the upcoming campaign',
  'Just wanted to share this',
  'Are you available this week?',
  'Some thoughts on the strategy',
  'Looking forward to our call',
  'Brief update from my end'
];

// Plain text bodies - NO links in week 1-2 (critical for warmup)
const bodiesWeek1 = [
  `Hi ${partnerName},\n\nJust wanted to follow up on our conversation from last week. I have been thinking about the approach we discussed and I think it could work really well.\n\nLet me know when you have a moment to chat about it.\n\nBest regards`,
  `Hey ${partnerName},\n\nHope your week is going well. I wanted to check in about the timeline for the next phase. Are we still on track for the dates we discussed?\n\nLet me know if anything has changed on your end.\n\nThanks`,
  `Hi ${partnerName},\n\nThanks for sending over those details yesterday. I have reviewed everything and it looks great. Just had a couple of small questions I wanted to run by you.\n\nAre you free for a quick call this week?\n\nBest`,
  `Hi ${partnerName},\n\nI finished putting together the notes from our meeting. The main action items are looking solid. I will start working on the first deliverable this week.\n\nLet me know if I missed anything important.\n\nRegards`,
  `Hey ${partnerName},\n\nJust a heads up - I made some updates to the shared document based on the feedback we received. Take a look when you get a chance and let me know what you think.\n\nTalk soon`,
  `Hi ${partnerName},\n\nWanted to share a quick update on the progress so far. Things are moving along nicely and we should have the first draft ready by end of week.\n\nHappy to walk you through it whenever you are available.\n\nBest regards`,
  `Hey ${partnerName},\n\nI came across some interesting data points that are relevant to our project. I think they could help strengthen our approach significantly.\n\nWould love to discuss when you have a few minutes.\n\nCheers`,
  `Hi ${partnerName},\n\nThanks for the great discussion earlier. I have been mulling over the points you raised and I think you are right about pivoting the strategy.\n\nLet us schedule some time to map out the next steps.\n\nBest`,
  `Hey ${partnerName},\n\nJust circling back on the proposal we discussed. I have made the revisions you suggested and I think it is in much better shape now.\n\nWould appreciate your final thoughts before we move forward.\n\nThanks`,
  `Hi ${partnerName},\n\nQuick update from my end - the team is aligned on the direction we discussed. Everyone is excited about the potential impact.\n\nLet me know if you need anything else from me.\n\nRegards`
];

const subject = subjects[Math.floor(Math.random() * subjects.length)];
const body = bodiesWeek1[Math.floor(Math.random() * bodiesWeek1.length)];

// Human-like random delay before sending (2-12 minutes)
const humanDelay = Math.floor(Math.random() * 10) + 2;

return [{
  json: {
    ...$input.first().json,
    subject,
    body,
    humanDelay,
    generatedAt: new Date().toISOString()
  }
}];

// Increment daily counter
const staticData = $getWorkflowStaticData('global');
staticData.sentToday = (staticData.sentToday || 0) + 1;

return [{
  json: {
    status: 'sent_successfully',
    to: $input.first().json.partnerEmail,
    toName: $input.first().json.partnerName,
    subject: $input.first().json.subject,
    week: $input.first().json.week,
    sentToday: staticData.sentToday,
    timestamp: new Date().toISOString()
  }
}];
